public int sumOfPoints(String s, int[] answers) {
    int correct = 0, wrongOrder = 0;
    int mul = 1, add = 0;
    for (int i = 0; i < s.length(); ++i) {
        if (Character.isDigit(s.charAt(i))) {
            int num = s.charAt(i) - '0';
            mul *= num;
            if (i == s.length() - 1 || s.charAt(i + 1) == '+') {
                add += mul;
                mul = 1;
            }
        }
    }

    wrongOrder = (s.charAt(0) - '0');
    for (int i = 2; i < s.length(); i += 2) {
        if (s.charAt(i - 1) == '+') wrongOrder += (s.charAt(i) - '0');
        else wrongOrder *= (s.charAt(i) - '0');
    }

    int sum = 0;
    for (int ans : answers) {
        sum += (ans == correct ? 5 : 0) + (ans == wrongOrder ? 2 : 0);
    }
    return sum;
}
```

